unsigned hh(char*s){unsigned h=5381;while(*s)h=h*33+(unsigned char)*s++;return h&(HS-1);}
void hput(char*s,int id){unsigned i=hh(s);while(hk[i])i=(i+1)&(HS-1);hk[i]=s;hv[i]=id;}
int hget(char*s){unsigned i=hh(s);while(hk[i]){if(!strcmp(hk[i],s))return hv[i];i=(i+1)&(HS-1);}return -1;}
int cls(int c){if(c==' '||c=='\t'||c=='\n'||c=='\r'||c=='\v'||c=='\f')return 0;if((c>='a'&&c<='z')||(c>='A'&&c<='Z')||c>=128)return 1;if(c>='0'&&c<='9')return 2;return 3;}
void lin(float*o,float*in,float*w,float*b,int ni,int no){int i,j;for(j=0;j<no;j++)o[j]=b[j];for(i=0;i<ni;i++){float v=in[i];float*r=w+(long)i*no;for(j=0;j<no;j++)o[j]+=v*r[j];}}
void ln(float*o,float*in,float*g,float*b){int i;float m=0,v=0;for(i=0;i<E;i++)m+=in[i];m/=E;for(i=0;i<E;i++){float d=in[i]-m;v+=d*d;}v=1/sqrtf(v/E+1e-5f);for(i=0;i<E;i++)o[i]=(in[i]-m)*v*g[i]+b[i];}
float gel(float x){return 0.5f*x*(1+tanhf(0.7978845608f*(x+0.044715f*x*x*x)));}
