void pre(unsigned char*s){int n=strlen((char*)s),p=0;while(p<n){
 if(s[p]=='\''&&p+1<n){if(p+2<n&&((s[p+1]=='r'&&s[p+2]=='e')||(s[p+1]=='v'&&s[p+2]=='e')||(s[p+1]=='l'&&s[p+2]=='l'))){bpe(s+p,3);p+=3;continue;}char a=s[p+1];if(a=='s'||a=='t'||a=='m'||a=='d'){bpe(s+p,2);p+=2;continue;}}
 int st=p,lead=(s[p]==' '&&p+1<n&&cls(s[p+1])!=0),cp=lead?p+1:p,k=cls(s[cp]);
