 else{int q=cp;while(q<n&&cls(s[q])==k)q++;bpe(s+st,q-st);p=q;}}}
void lp(int l,float**o){float*b=W+BASE+(long)l*PL;o[0]=b;o[1]=b+E;o[2]=b+2*E;o[3]=o[2]+(long)E*A;o[4]=o[3]+A;o[5]=o[4]+(long)E*E;o[6]=o[5]+E;o[7]=o[6]+E;o[8]=o[7]+E;o[9]=o[8]+(long)E*C;o[10]=o[9]+C;o[11]=o[10]+(long)C*E;}
