 ln(tmp,X+(T-1)*E,lnfg,lnfb);
 for(j=0;j<V;j++){float s=0,*w=wte+(long)j*E;for(i=0;i<E;i++)s+=tmp[i]*w[i];logit[j]=s;}}
void dec(char*s){unsigned char c;int cp;while((c=*s)){if(c<0x80){cp=c;s++;}else{cp=((c&0x1F)<<6)|((unsigned char)s[1]&0x3F);s+=2;}putchar(u2b[cp]);}}
